// Component to fetch and display emergency profile
// Patient ID is taken from URL parameter

import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import "./App.css";

function EmergencyProfile() {
  const { patientId } = useParams(); // get patientId from URL
  const [data, setData] = useState(null);
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch data from Flask backend
    fetch(`http://127.0.0.1:5000/emergency/${patientId}`)
      .then((response) => response.json())
      .then((result) => {
        setLoading(false);

        // If backend returns message
        if (result.message) {
          setMessage(result.message);
        } else {
          setData(result);
        }
      })
      .catch(() => {
        setLoading(false);
        setMessage("Server not reachable");
      });
  }, [patientId]);

  if (loading) {
    return <h2 className="center">Loading...</h2>;
  }

  // Display backend messages
  if (message === "Profile not public visible") {
    return <h2 className="center">Profile is not visible</h2>;
  }

  if (message === "No record found") {
    return <h2 className="center">No record found</h2>;
  }

  if (message) {
    return <h2 className="center">{message}</h2>;
  }

  // Display profile data
  return (
    <div className="container">
      <h1>Emergency Profile</h1>

      <div className="card">
        <p><strong>Name:</strong> {data.name}</p>
        <p><strong>Address:</strong> {data.address}</p>
        <p><strong>Gender:</strong> {data.gender}</p>
        <p><strong>Contact Name:</strong> {data.contact_name}</p>
        <p><strong>Contact Phone:</strong> {data.contact_phone}</p>
        <p><strong>Chronic Conditions:</strong> {data.chronic_conditions}</p>
        <p><strong>Blood Group:</strong> {data.blood_group}</p>
        <p><strong>Allergies:</strong> {data.allergies}</p>
      </div>
    </div>
  );
}

export default EmergencyProfile;
